(function(){
  "use strict";

  const AVATAR_SRC = "data:image/png;base64,";

  const floorplan = document.getElementById('floorplan');
  const charWrap = document.getElementById('char-wrap');
  const charSprite = document.getElementById('char-sprite');
  const bubble = document.getElementById('speech-bubble');
  const roomLab = document.getElementById('room-lab');
  const roomStudio = document.getElementById('room-studio');
  const apartmentView = document.getElementById('apartment-view');
  const roomView = document.getElementById('room-view');
  const roomBanner = document.getElementById('room-banner');
  const roomBannerTitle = document.getElementById('room-banner-title');
  const roomBannerDesc = document.getElementById('room-banner-desc');
  const entryList = document.getElementById('entry-list');
  const backBtn = document.getElementById('back-btn');
  const crumbs = document.getElementById('crumbs');
  const labCount = document.getElementById('lab-count');
  const studioCount = document.getElementById('studio-count');

  charSprite.src = AVATAR_SRC;

  // ---------- positions within the floorplan (percent-based, responsive) ----------
  let posPct = 50; // horizontal % across the whole floorplan width
  let facing = 'right';
  let walkTimer = null;
  let bubbleTimer = null;
  let currentZone = 'home'; // 'home' | 'lab' | 'studio'

  function isStacked(){
    return window.matchMedia('(max-width: 720px)').matches;
  }

  function placeCharacter(animate){
    const rect = floorplan.getBoundingClientRect();
    if(isStacked()){
      // stacked: x stays centered, y moves between two rooms vertically
      const labRect = roomLab.getBoundingClientRect();
      const studioRect = roomStudio.getBoundingClientRect();
      const targetRect = currentZone === 'studio' ? studioRect : labRect;
      const topPx = (targetRect.bottom - rect.top) - 14;
      const leftPx = rect.width / 2;
      charWrap.style.left = leftPx + 'px';
      charWrap.style.top = topPx + 'px';
    } else {
      const leftPx = (posPct/100) * rect.width;
      const labRect = roomLab.getBoundingClientRect();
      const bottomPx = (labRect.bottom - rect.top) - 14;
      charWrap.style.left = leftPx + 'px';
      charWrap.style.top = bottomPx + 'px';
    }
  }

  function updateZoneFromPos(){
    const rect = floorplan.getBoundingClientRect();
    const midpoint = rect.width / 2;
    const leftPx = (posPct/100) * rect.width;
    const zone = leftPx < midpoint ? 'lab' : 'studio';
    if(zone !== currentZone){
      currentZone = zone;
      showDialogue(zone, true);
    }
  }

  function setFacing(dir){
    facing = dir;
    charSprite.classList.toggle('face-left', dir === 'left');
  }

  function walkTo(targetPct){
    clearTimeout(walkTimer);
    const dir = targetPct < posPct ? 'left' : 'right';
    setFacing(dir);
    charSprite.classList.add('walking');
    posPct = Math.max(8, Math.min(92, targetPct));
    placeCharacter(true);
    updateZoneFromPos();
    walkTimer = setTimeout(()=>{
      charSprite.classList.remove('walking');
    }, 1150);
  }

  function nudge(deltaPct){
    walkTo(posPct + deltaPct);
  }

  function pickLine(zone){
    const lines = DIALOGUE[zone] || DIALOGUE.home;
    return lines[Math.floor(Math.random()*lines.length)];
  }

  function showDialogue(zone, auto){
    const text = pickLine(zone);
    bubble.textContent = text;
    bubble.classList.add('show');
    clearTimeout(bubbleTimer);
    bubbleTimer = setTimeout(()=>{
      bubble.classList.remove('show');
    }, auto ? 3600 : 4200);
  }

  // ---------- keyboard movement ----------
  window.addEventListener('keydown', (e)=>{
    if(roomView.style.display === 'block') return; // no walking while inside a room
    if(e.key === 'ArrowLeft'){
      e.preventDefault();
      nudge(-9);
    } else if(e.key === 'ArrowRight'){
      e.preventDefault();
      nudge(9);
    }
  });

  // tapping the character herself gives a little greeting
  charSprite.addEventListener('click', ()=> showDialogue(currentZone, false));

  // ---------- room entry ----------
  function renderEntries(zone){
    entryList.innerHTML = '';
    const list = ENTRIES[zone] || [];
    list.forEach(entry=>{
      const card = document.createElement('article');
      card.className = 'entry-card';
      const meta = document.createElement('div');
      meta.className = 'entry-meta';
      meta.innerHTML = `<span>${entry.date}</span><span class="sep">&middot;</span><span class="tag">${entry.tag}</span>`;
      const h3 = document.createElement('h3');
      h3.textContent = entry.title;
      const p = document.createElement('p');
      p.textContent = entry.body;
      card.appendChild(meta);
      card.appendChild(h3);
      card.appendChild(p);
      if(entry.placeholder){
        const flag = document.createElement('span');
        flag.className = 'placeholder-flag';
        flag.textContent = '// placeholder — replace with your real entry in data.js';
        card.appendChild(flag);
      }
      entryList.appendChild(card);
    });

    const addCard = document.createElement('div');
    addCard.className = 'add-entry-card';
    addCard.textContent = zone === 'lab'
      ? '+ add your next entry to ENTRIES.lab in data.js'
      : '+ add your next entry to ENTRIES.studio in data.js';
    entryList.appendChild(addCard);
  }

  function enterRoom(zone){
    apartmentView.style.display = 'none';
    roomView.style.display = 'block';
    roomBanner.className = 'room-banner ' + zone;
    roomView.className = zone === 'studio' ? 'room-view studio' : 'room-view lab';

    if(zone === 'lab'){
      roomBannerTitle.textContent = 'coding lab';
      roomBannerDesc.textContent = 'internship logs, debugging spirals, things that finally compiled.';
    } else {
      roomBannerTitle.textContent = 'ceramics studio';
      roomBannerDesc.textContent = 'glaze tests, wheel notes, and the occasional ML fellowship thought.';
    }

    renderEntries(zone);
    updateCrumbs(zone);
    window.scrollTo({top:0, behavior:'smooth'});
  }

  function leaveRoom(){
    roomView.style.display = 'none';
    apartmentView.style.display = 'block';
    updateCrumbs('home');
    requestAnimationFrame(()=> placeCharacter(false));
  }

  function updateCrumbs(zone){
    crumbs.innerHTML = '';
    const homeBtn = document.createElement('button');
    homeBtn.type = 'button';
    homeBtn.textContent = 'home';
    homeBtn.dataset.nav = 'home';
    homeBtn.addEventListener('click', leaveRoom);
    crumbs.appendChild(homeBtn);

    if(zone !== 'home'){
      const sep = document.createElement('span');
      sep.className = 'sep';
      sep.textContent = '/';
      crumbs.appendChild(sep);

      const roomBtn = document.createElement('button');
      roomBtn.type = 'button';
      roomBtn.setAttribute('aria-current', 'true');
      roomBtn.textContent = zone === 'lab' ? 'coding lab' : 'ceramics studio';
      crumbs.appendChild(roomBtn);
    } else {
      homeBtn.setAttribute('aria-current', 'true');
    }
  }

  // room click/keyboard activation
  [ [roomLab,'lab'], [roomStudio,'studio'] ].forEach(([el, zone])=>{
    el.addEventListener('click', ()=> enterRoom(zone));
    el.addEventListener('keydown', (e)=>{
      if(e.key === 'Enter' || e.key === ' '){
        e.preventDefault();
        enterRoom(zone);
      }
    });
  });

  backBtn.addEventListener('click', leaveRoom);

  // ---------- entry counts ----------
  labCount.textContent = ENTRIES.lab.length + ' entries';
  studioCount.textContent = ENTRIES.studio.length + ' entries';

  // ---------- keep the speech bubble from clipping off the floorplan edges ----------
  function clampBubble(){
    const floorRect = floorplan.getBoundingClientRect();
    bubble.style.transform = 'translateX(-50%) scale(' + (bubble.classList.contains('show') ? 1 : 0.85) + ')';
    const bubbleRect = bubble.getBoundingClientRect();
    let shift = 0;
    const margin = 10;
    if(bubbleRect.left < floorRect.left + margin){
      shift = (floorRect.left + margin) - bubbleRect.left;
    } else if(bubbleRect.right > floorRect.right - margin){
      shift = (floorRect.right - margin) - bubbleRect.right;
    }
    const scale = bubble.classList.contains('show') ? 1 : 0.85;
    bubble.style.transform = shift !== 0
      ? `translateX(calc(-50% + ${shift}px)) scale(${scale})`
      : `translateX(-50%) scale(${scale})`;
  }

  const baseShowDialogue = showDialogue;
  showDialogue = function(zone, auto){
    baseShowDialogue(zone, auto);
    requestAnimationFrame(clampBubble);
  };

  // ---------- init ----------
  let initialized = false;
  function init(){
    if(initialized) return;
    initialized = true;
    placeCharacter(false);
    setTimeout(()=> showDialogue('home', true), 600);
  }

  window.addEventListener('resize', ()=> placeCharacter(false));
  if(document.readyState === 'complete'){
    init();
  } else {
    window.addEventListener('load', init);
  }

})();
